// Icon returns an SVG icon as template.HTML, ready for inline use.
// Usage in templates: {{icon "search" "w-5 h-5"}}
func Icon(name, class string) template.HTML {
	ic, ok := catalog[name]
	if !ok {
		return template.HTML("<!-- icon not found: " + template.HTMLEscapeString(name) + " -->")
	}
	if ic.Stroke {
		return template.HTML(fmt.Sprintf(
			`<svg class="%s" viewBox="%s" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" xmlns="http://www.w3.org/2000/svg">%s</svg>`,
			class, ic.ViewBox, ic.Body,
		))
	}
	return template.HTML(fmt.Sprintf(
		`<svg class="%s" viewBox="%s" fill="currentColor" xmlns="http://www.w3.org/2000/svg">%s</svg>`,
		class, ic.ViewBox, ic.Body,
	))
}
